import React, { useState } from 'react';

const AdminPanel = ({ rooms, archive, dailyLogs, threshold, setThreshold, users, setUsers }) => {
    const [view, setView] = useState('stats'); // stats, archive, users, products

    // Считаем общую статистику по товарам (на основе того, что в комнатах сейчас)
    const getProductStats = () => {
        let stats = {};
        rooms.forEach(room => {
            room.inventory.forEach(item => {
                if (!stats[item.name]) stats[item.name] = { total: 0, expired: 0 };
                stats[item.name].total += item.count;
                // Если срок меньше порога — считаем как "под замену"
                if (item.expiry && item.expiry !== 'нет') {
                    const diff = (new Date(item.expiry) - new Date()) / (1000 * 60 * 60 * 24);
                    if (diff < threshold) stats[item.name].expired += 1;
                }
            });
        });
        return stats;
    };

    const productStats = getProductStats();

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Admin Dashboard</h2>

            <div className="threshold-buttons" style={{ marginBottom: '20px', overflowX: 'auto' }}>
                <button className={`t-btn ${view === 'stats' ? 'active' : ''}`} onClick={() => setView('stats')}>LIVE</button>
                <button className={`t-btn ${view === 'archive' ? 'active' : ''}`} onClick={() => setView('archive')}>АРХИВ</button>
                <button className={`t-btn ${view === 'products' ? 'active' : ''}`} onClick={() => setView('products')}>ТОВАРЫ</button>
                <button className={`t-btn ${view === 'users' ? 'active' : ''}`} onClick={() => setView('users')}>ПЕРСОНАЛ</button>
            </div>

            {view === 'stats' && (
                <div className="fade-in">
                    <div className="admin-stats-grid">
                        <div className="stat-card">
                            <span className="stat-value">{rooms.filter(r => r.status === 'checked').length}</span>
                            <span className="stat-label">Проверено сегодня</span>
                        </div>
                        <div className="stat-card">
                            <span className="stat-value">{rooms.filter(r => r.status === 'dnd').length}</span>
                            <span className="stat-label">DND</span>
                        </div>
                    </div>
                    <div className="admin-settings-section">
                        <h3>Лента событий</h3>
                        <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
                            {dailyLogs.map((log, i) => (
                                <div key={i} style={{ padding: '8px 0', borderBottom: '1px solid #eee', fontSize: '12px' }}>
                                    <b>{log.time}</b> | {log.staff} | №{log.roomId} — <span style={{color: log.action === 'DND' ? 'red' : 'green'}}>{log.action}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {view === 'products' && (
                <div className="admin-settings-section fade-in">
                    <h3>Статистика по продукции</h3>
                    <table style={{ width: '100%', fontSize: '13px', textAlign: 'left' }}>
                        <thead>
                        <tr style={{ color: '#999' }}>
                            <th>Товар</th>
                            <th>В наличии</th>
                            <th>К замене</th>
                        </tr>
                        </thead>
                        <tbody>
                        {Object.keys(productStats).map(name => (
                            <tr key={name} style={{ borderBottom: '1px solid #f0f0f0' }}>
                                <td style={{ padding: '10px 0' }}>{name}</td>
                                <td>{productStats[name].total} шт.</td>
                                <td style={{ color: productStats[name].expired > 0 ? 'red' : 'inherit' }}>
                                    {productStats[name].expired} шт.
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            )}

            {view === 'archive' && (
                <div className="admin-settings-section fade-in">
                    <h3>Архив (История за 00:00)</h3>
                    {archive.map((day, i) => (
                        <div key={i} style={{ marginBottom: '10px', padding: '10px', background: '#f8f9fa', borderRadius: '8px' }}>
                            <b>{day.date}</b>: {day.stats.checked} Проверок, {day.stats.dnd} DND.
                        </div>
                    ))}
                </div>
            )}

            {view === 'users' && (
                <div className="admin-settings-section fade-in">
                    <h3>Сотрудники</h3>
                    {users.map((u, i) => (
                        <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0' }}>
                            <span>{u.login} <small>({u.role})</small></span>
                            <button onClick={() => setUsers(users.filter(usr => usr.login !== u.login))} style={{border:'none', color:'red', background:'none'}}>Удалить</button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default AdminPanel;
